// src/App.js
import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';

// importa respetando nombre y extensión exacta
import Login from './templates/login.jsx';
import Register from './templates/register.jsx';

// estilos globales (después de mover style.css a src/)
import './style.css';

function App() {
  return (
    <Router>
      <Routes>
        {/* ruta raíz -> login */}
        <Route path="/" element={<Navigate to="/login" replace />} />

        {/* auth */}
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />

        {/* cuando migres mision.html -> mision.jsx, agrega aquí la ruta */}
        {/* <Route path="/mision" element={<Mision />} /> */}

        {/* 404 */}
        <Route path="*" element={<Navigate to="/login" replace />} />
      </Routes>
    </Router>
  );
}

export default App;
